-- Item Smash (Old Man Exchange / Item Disassemble) table
-- Migrated from MSSQL ITEM_SMASH (205 rows)

CREATE TABLE IF NOT EXISTS item_smash (
    n_index INTEGER NOT NULL PRIMARY KEY,
    item_id INTEGER NOT NULL DEFAULT 0,
    count SMALLINT NOT NULL DEFAULT 0,
    rate SMALLINT NOT NULL DEFAULT 0
);

ON CONFLICT DO NOTHING;

